import java.io.IOException;

public class SecureCommandExecution {

    public static void main(String[] args) throws IOException {
        String userInput = "example.txt; rm -rf /"; // User input with malicious command

        // Safe code - using ProcessBuilder to execute the command securely
        ProcessBuilder processBuilder = new ProcessBuilder("cat", userInput);
        processBuilder.inheritIO();
        Process process = processBuilder.start();

        int exitCode;
        try {
            exitCode = process.waitFor();
            if (exitCode == 0) {
                System.out.println("Command executed successfully.");
            } else {
                System.out.println("Error executing the command.");
            }
        } catch (InterruptedException e) {
            System.err.println("Error executing the command: " + e.getMessage());
            Thread.currentThread().interrupt();
        }
    }
}

